## Callback Memory Management

Callbacks from native code require special handling:

```csharp
public class GtkEventHandler
{
    // Keep delegate alive to prevent GC collection
    private readonly GtkCallback _callback;
    private GCHandle _callbackHandle;

    public GtkEventHandler()
    {
        _callback = OnGtkEvent;
        _callbackHandle = GCHandle.Alloc(_callback);
    }

    public void Connect(IntPtr widget, string signal)
    {
        StringMarshalHelper.WithUtf8String(signal, signalPtr =>
        {
            var callbackPtr = Marshal.GetFunctionPointerForDelegate(_callback);
            g_signal_connect_data(
                widget,
                signalPtr,
                callbackPtr,
                IntPtr.Zero,
                IntPtr.Zero,
                0
            );
        });
    }

    private void OnGtkEvent(IntPtr widget, IntPtr userData)
    {
        // Handle event
    }

    public void Dispose()
    {
        if (_callbackHandle.IsAllocated)
        {
            _callbackHandle.Free();
        }
    }

    [UnmanagedFunctionPointer(CallingConvention.Cdecl)]
    private delegate void GtkCallback(IntPtr widget, IntPtr userData);

    [DllImport("libgobject-2.0.so.0")]
    private static extern ulong g_signal_connect_data(
        IntPtr instance,
        IntPtr signal,
        IntPtr callback,
        IntPtr data,
        IntPtr destroyData,
