## Memory Pool for Frequent Allocations

Reduce allocation overhead with pooling:

```csharp
public class NativeMemoryPool
{
    private readonly ConcurrentBag<IntPtr> _pool = new();
    private readonly int _blockSize;
    private readonly int _maxPoolSize;

    public NativeMemoryPool(int blockSize, int maxPoolSize = 100)
    {
        _blockSize = blockSize;
        _maxPoolSize = maxPoolSize;
    }

    public IntPtr Rent()
    {
        if (_pool.TryTake(out var ptr))
        {
            // Reuse pooled memory
            return ptr;
        }

        // Allocate new block
        return Marshal.AllocHGlobal(_blockSize);
    }

    public void Return(IntPtr ptr)
    {
        if (_pool.Count < _maxPoolSize)
        {
            // Return to pool
            _pool.Add(ptr);
        }
        else
        {
            // Pool full, free immediately
            Marshal.FreeHGlobal(ptr);
        }
    }

    public void Clear()
    {
        while (_pool.TryTake(out var ptr))
        {
            Marshal.FreeHGlobal(ptr);
        }
    }
}
```

## Detecting Memory Leaks

Implement diagnostics to track native allocations:

```csharp
public static class NativeMemoryTracker
{
    private static readonly ConcurrentDictionary<IntPtr, AllocationInfo> _allocations = new();

    private record AllocationInfo(int Size, string StackTrace, DateTime Timestamp);

    public static IntPtr Allocate(int size, [CallerMemberName] string caller = "")
    {
        var ptr = Marshal.AllocHGlobal(size);

        _allocations[ptr] = new AllocationInfo(
            size,
            Environment.StackTrace,
            DateTime.UtcNow
        );

        return ptr;
    }

    public static void Free(IntPtr ptr)
    {
        _allocations.TryRemove(ptr, out _);
        Marshal.FreeHGlobal(ptr);
    }

    public static void ReportLeaks()
    {
        var leaks = _allocations.ToArray();

        if (leaks.Length == 0)
        {
            Console.WriteLine("✓ No memory leaks detected");
            return;
        }

        Console.WriteLine($"⚠ {leaks.Length} potential leaks detected:");

        foreach (var (ptr, info) in leaks)
        {
            var age = DateTime.UtcNow - info.Timestamp;
            Console.WriteLine($"  Ptr: {ptr:X}, Size: {info.Size} bytes, Age: {age.TotalSeconds:F1}s");
            Console.WriteLine($"  Allocated at:\n{info.StackTrace}");
        }
    }
}
