## Detecting GPU Capabilities

Query GPU capabilities to make informed decisions:

```csharp
public class GpuCapabilities
{
    public static GpuInfo DetectCapabilities()
    {
        var glInterface = GRGlInterface.Create();
        if (glInterface == null)
        {
            return new GpuInfo { Available = false };
        }

        using var context = GRContext.CreateGl(glInterface);

        return new GpuInfo
        {
            Available = true,
            MaxTextureSize = context.GetMaxTextureSize(),
            Vendor = GetGLString(GL_VENDOR),
            Renderer = GetGLString(GL_RENDERER),
            Version = GetGLString(GL_VERSION)
        };
    }

    [DllImport("libGL.so.1")]
    private static extern IntPtr glGetString(uint name);

    private static string GetGLString(uint name)
    {
        var ptr = glGetString(name);
        return Marshal.PtrToStringAnsi(ptr) ?? "Unknown";
    }

    private const uint GL_VENDOR = 0x1F00;
    private const uint GL_RENDERER = 0x1F01;
    private const uint GL_VERSION = 0x1F02;
}

public class GpuInfo
{
    public bool Available { get; set; }
    public int MaxTextureSize { get; set; }
    public string Vendor { get; set; } = "";
    public string Renderer { get; set; } = "";
    public string Version { get; set; } = "";

    public bool IsIntelIntegrated => 
        Vendor.Contains("Intel", StringComparison.OrdinalIgnoreCase);

    public bool IsNvidia => 
        Vendor.Contains("NVIDIA", StringComparison.OrdinalIgnoreCase);

    public bool IsAMD => 
        Vendor.Contains("AMD", StringComparison.OrdinalIgnoreCase) ||
        Vendor.Contains("ATI", StringComparison.OrdinalIgnoreCase);
}
```

## Decision Matrix

| Scenario | Recommended Backend | Reason |
|----------|-------------------|--------|
| Simple business forms | Software | Lower overhead for basic shapes |
| Image-heavy applications | GPU | Hardware-accelerated image compositing |
| Data visualization | GPU | Complex paths and gradients |
| Text-heavy UIs | Software | Font rendering is fast on CPU |
| Animations | GPU | Smooth 60 FPS with hardware acceleration |
| Virtual machines | Software | GPU passthrough often unavailable |
| Low-end hardware | Software | Integrated GPUs may be slower |

## Fallback Strategy

Always implement graceful fallback:

```csharp
public class RenderingEngineFactory
{
    public static IRenderingEngine Create()
    {
        // Try GPU first
        var gpuEngine = new GpuRenderingEngine();
        if (gpuEngine.Initialize(GetGLContext(), 1920, 1080))
        {
            Console.WriteLine("✓ Using GPU rendering");
            return gpuEngine;
        }

        // Fallback to software
        Console.WriteLine("⚠ GPU unavailable, using software rendering");
        var softwareEngine = new SoftwareRenderingEngine();
        softwareEngine.Initialize(1920, 1080);
        return softwareEngine;
    }
}
```

The key is measuring real-world performance on your target hardware and choosing the backend that delivers the best user experience.

OpenMaui's Linux implementation relies heavily on P/Invoke for native interop with GTK, X11, and Wayland. Improper memory management in these scenarios leads to leaks, crashes, and degraded performance. This section covers essential patterns for safe native resource handling.

## Understanding Native Memory Lifecycle

When you call native functions, you're crossing the managed/unmanaged boundary. The .NET garbage collector doesn't track native allocations, so you must manually manage their lifecycle.

## SafeHandle Pattern for Native Resources

Use `SafeHandle` for automatic cleanup of native resources:

```csharp
public class GtkWidgetHandle : SafeHandle
{
    public GtkWidgetHandle() : base(IntPtr.Zero, true)
    {
    }

    public GtkWidgetHandle(IntPtr handle) : base(IntPtr.Zero, true)
    {
        SetHandle(handle);
    }

    public override bool IsInvalid => handle == IntPtr.Zero;

    protected override bool ReleaseHandle()
    {
        if (!IsInvalid)
        {
            // Properly unreference GTK widget
            gtk_widget_destroy(handle);
            g_object_unref(handle);
        }
        return true;
    }

    [DllImport("libgtk-3.so.0")]
    private static extern void gtk_widget_destroy(IntPtr widget);

    [DllImport("libgobject-2.0.so.0")]
    private static extern void g_object_unref(IntPtr obj);
}
```

Use it in your code:

```csharp
public class GtkButton : IDisposable
{
    private readonly GtkWidgetHandle _handle;

    public GtkButton(string label)
    {
        var labelPtr = Marshal.StringToHGlobalAnsi(label);
        try
        {
            var widget = gtk_button_new_with_label(labelPtr);
            _handle = new GtkWidgetHandle(widget);
        }
        finally
        {
            Marshal.FreeHGlobal(labelPtr);
        }
    }

    public void Dispose()
    {
        _handle?.Dispose();
    }

    [DllImport("libgtk-3.so.0")]
    private static extern IntPtr gtk_button_new_with_label(IntPtr label);
}
```

## String Marshaling

String conversions are a common source of memory leaks:

```csharp
public static class StringMarshalHelper
{
    // Allocate UTF-8 string for native code
    public static IntPtr StringToUtf8(string str)
    {
        if (str == null)
            return IntPtr.Zero;

        var bytes = Encoding.UTF8.GetByteCount(str);
        var ptr = Marshal.AllocHGlobal(bytes + 1);

        unsafe
        {
            fixed (char* chars = str)
            {
                var bytePtr = (byte*)ptr;
                Encoding.UTF8.GetBytes(chars, str.Length, bytePtr, bytes);
                bytePtr[bytes] = 0; // Null terminator
            }
        }

        return ptr;
    }

    // Convert native UTF-8 string to managed
    public static string? Utf8ToString(IntPtr ptr)
    {
        if (ptr == IntPtr.Zero)
            return null;

        var length = 0;
        unsafe
        {
            var bytePtr = (byte*)ptr;
            while (bytePtr[length] != 0)
                length++;
        }

        var bytes = new byte[length];
        Marshal.Copy(ptr, bytes, 0, length);

        return Encoding.UTF8.GetString(bytes);
    }

    // Use for temporary strings (auto-freed)
    public static void WithUtf8String(string str, Action<IntPtr> action)
    {
        var ptr = StringToUtf8(str);
        try
        {
            action(ptr);
        }
        finally
        {
            Marshal.FreeHGlobal(ptr);
        }
    }
}
```

