## Comprehensive Benchmarking Framework

```csharp
public class PerformanceBenchmark
{
    private readonly Dictionary<string, List<double>> _measurements = new();
    private readonly Stopwatch _stopwatch = new();

    public IDisposable Measure(string operation)
    {
        return new MeasurementScope(this, operation);
    }

    private class MeasurementScope : IDisposable
    {
        private readonly PerformanceBenchmark _benchmark;
        private readonly string _operation;
        private readonly Stopwatch _sw;

        public MeasurementScope(PerformanceBenchmark benchmark, string operation)
        {
            _benchmark = benchmark;
            _operation = operation;
            _sw = Stopwatch.StartNew();
        }

        public void Dispose()
        {
            _sw.Stop();
            _benchmark.RecordMeasurement(_operation, _sw.Elapsed.TotalMilliseconds);
        }
    }

    private void RecordMeasurement(string operation, double milliseconds)
    {
        if (!_measurements.ContainsKey(operation))
        {
            _measurements[operation] = new List<double>();
        }

        _measurements[operation].Add(milliseconds);
    }

    public BenchmarkReport GenerateReport()
    {
        var report = new BenchmarkReport();

        foreach (var (operation, measurements) in _measurements)
        {
            var stats = new BenchmarkStats
            {
                Operation = operation,
                Count = measurements.Count,
                Min = measurements.Min(),
                Max = measurements.Max(),
                Average = measurements.Average(),
                Median = CalculateMedian(measurements),
                P95 = CalculatePercentile(measurements, 0.95),
                P99 = CalculatePercentile(measurements, 0.99)
            };

            report.Stats.Add(stats);
        }

        return report;
    }

    private double CalculateMedian(List<double> values)
    {
        var sorted = values.OrderBy(v => v).ToList();
        var mid = sorted.Count / 2;

        if (sorted.Count % 2 == 0)
            return (sorted[mid - 1] + sorted[mid]) / 2.0;
        else
            return sorted[mid];
    }

    private double CalculatePercentile(List<double> values, double percentile)
    {
        var sorted = values.OrderBy(v => v).ToList();
        var index = (int)Math.Ceiling(percentile * sorted.Count) - 1;
        return sorted[Math.Max(0, index)];
    }
}

public class BenchmarkReport
{
    public List<BenchmarkStats> Stats { get; } = new();

    public void Print()
    {
        Console.WriteLine("\n=== Performance Benchmark Report ===");
        Console.WriteLine($"{{"Operation",-30}} {{"Count",8}} {{"Min",10}} {{"Avg",10}} {{"Median",10}} {{"P95",10}} {{"P99",10}} {{"Max",10}}");
        Console.WriteLine(new string('-', 110));

        foreach (var stat in Stats.OrderByDescending(s => s.Average))
        {
            Console.WriteLine(
                $"{stat.Operation,-30} {stat.Count,8} {stat.Min,10:F2} {stat.Average,10:F2} " +
                $"{stat.Median,10:F2} {stat.P95,10:F2} {stat.P99,10:F2} {stat.Max,10:F2}"
            );
        }
    }
}

